parameters.jsCode:
// Parse Supabase webhook or portal POST
// Supabase webhooks send: { type, table, record, old_record }
const body = $input.first().json.body || $input.first().json;

let prospect;
if (body.record) {
  // Supabase webhook format
  prospect = body.record;
} else {
  // Direct POST from portal
  prospect = body;
}

const status = prospect.eligibility_status;
if (!status || !['yes', 'no', 'maybe'].includes(status)) {
  throw new Error('Invalid or missing eligibility_status: ' + status);
}

return [{
  json: {
    prospect_id: prospect.id,
    first_name: prospect.first_name,
    last_name: prospect.last_name,
    email: prospect.email,
    phone: prospect.phone,
    program_interest: prospect.program_interest,
    eligibility_status: status,
    full_name: `${prospect.first_name} ${prospect.last_name}`
  }
}];

// Generate unique application link for eligible prospect
const prospectId = $json.prospect_id;
const applicationUrl = `https://portal.coineducation.com/application?prospect=${prospectId}`;

return [{
  json: {
    ...$json,
    application_url: applicationUrl
  }
}];

